if(found&&matchType==='exact')return [{json:{...v,ledgerCompleted:true,needsGemini:false,category:row.category||'needs-review',source:'ledger_reuse',confidence:row.confidence??1,reasoning:row.reasoning||'Replayed completed ledger classification to restore Gmail commit state.'}}];
