const FINISH_REASONS={MAX_TOKENS:'Gemini output truncated (MAX_TOKENS); safe fallback to needs-review.',SAFETY:'Gemini safety filter blocked classification; safe fallback to needs-review.',RECITATION:'Gemini recitation filter triggered; safe fallback to needs-review.',LANGUAGE:'Gemini language filter triggered; safe fallback to needs-review.',BLOCKLIST:'Gemini blocklist filter triggered; safe fallback to needs-review.',PROHIBITED_CONTENT:'Gemini prohibited-content filter triggered; safe fallback to needs-review.',SPII:'Gemini sensitive-PII filter triggered; safe fallback to needs-review.',MODEL_ARMOR:'Gemini Model Armor blocked classification; safe fallback to needs-review.',OTHER:'Gemini stopped for unspecified reason; safe fallback to needs-review.',MALFORMED_FUNCTION_CALL:'Gemini malformed-function-call stop; safe fallback to needs-review.',UNEXPECTED_TOOL_CALL:'Gemini unexpected-tool-call stop; safe fallback to needs-review.',TOO_MANY_TOOL_CALLS:'Gemini too-many-tool-calls stop; safe fallback to needs-review.',IMAGE_SAFETY:'Gemini image-safety stop; safe fallback to needs-review.',IMAGE_PROHIBITED_CONTENT:'Gemini image prohibited-content stop; safe fallback to needs-review.',IMAGE_OTHER:'Gemini image-other stop; safe fallback to needs-review.',FINISH_REASON_UNSPECIFIED:'Gemini finish reason unspecified; safe fallback to needs-review.'};
function sanitize(s){return String(s||'').replace(/AIza[0-9A-Za-z\-_]{20,}/g,'[REDACTED_GOOGLE_KEY]').replace(/Bearer\s+[A-Za-z0-9._\-]+/gi,'Bearer [REDACTED]').replace(/[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}/gi,'[email]').slice(0,500);}
function fallback(reason,errorMessage=null){return [{json:{...original,category:'needs-review',source:'ai_failed',confidence:0,reasoning:reason,errorMessage:errorMessage?sanitize(errorMessage):null}}];}
const item=$input.first()?.json||{};
if(item.error)return fallback('Gemini API failed; safe fallback to needs-review.',item.error.message||item.error);
if(!Array.isArray(item.candidates)||item.candidates.length===0){const block=item.promptFeedback?.blockReason?` Block reason: ${item.promptFeedback.blockReason}.`:'';return fallback(`Gemini returned no candidates; safe fallback to needs-review.${block}`,null);}
try{
 const candidate=item.candidates?.[0]||{}; const finishReason=String(candidate.finishReason||'STOP').toUpperCase();
 if(finishReason&&finishReason!=='STOP')return fallback(FINISH_REASONS[finishReason]||`Gemini stopped with ${finishReason}; safe fallback to needs-review.`,null);
 const parts=candidate.content?.parts||[]; const textPart=parts.find(p=>!p.thought&&p.text)||parts.find(p=>p.text)||parts[0]; const text=textPart?.text;
 if(!text)return fallback('Gemini returned empty response text; safe fallback to needs-review.',null);
 const parsed=typeof text==='string'?JSON.parse(text):(item.category?item:null);
 if(!parsed||typeof parsed!=='object')return fallback('Gemini parse failed; safe fallback to needs-review.');
 const category=String(parsed.category||'').trim(); const confidence=Number(parsed.confidence??0);
 if(parsed.messageId&&parsed.messageId!==original.messageId)return fallback('Gemini messageId mismatch; safe fallback to needs-review.');
 if(!allowed.has(category))return fallback('Gemini returned invalid category; safe fallback to needs-review.');
 if(!Number.isFinite(confidence)||confidence<0.8||confidence>1)return [{json:{...original,category:'needs-review',source:'ai_low_confidence',confidence:Number.isFinite(confidence)?confidence:0,reasoning:sanitize(parsed.reasoning||'Low confidence; safe fallback to needs-review.'),errorMessage:null}}];
 return [{json:{...original,category,source:'ai',confidence,reasoning:sanitize(parsed.reasoning||'Classified by Gemini.'),errorMessage:null}}];
}catch(e){return fallback('Gemini parse failed; safe fallback to needs-review.',e.message);}

const j=$input.first().json;
const category=j.category||j.ruleCategory||'needs-review'; const source=j.source||j.ruleSource||(j.ruleCategory?'rule_matched':'ai'); const labelId=j.labelMap?.[category];
return [{json:{...j,category,source,confidence:j.confidence??(j.source==='metadata_empty'?0:(j.ruleCategory?1:0)),reasoning:j.reasoning||(j.source==='metadata_empty'?'No usable sender, subject, or snippet metadata was available.':(j.ruleCategory?'Matched sender rule.':'Prepared final category.')),categoryLabelId:labelId||null,labelReady:j.ledgerCheckFailed?false:Boolean(labelId&&j.processedLabelId&&j.messageId)}}];

const prepared=(()=>{try{return $('Prepare Final Category').first().json;}catch{return $('Validate Input').first().json;}})(); const current=$input.first()?.json||{};
const err=current.error?.message||current.error||prepared.errorMessage||'Unknown Gmail processing error'; let failureStage='processing';
function safeNode(name){try{return $(name).first()?.json||null;}catch{return null;}}
if(prepared.ledgerCheckFailed)failureStage='ledger_check_failed'; else if(prepared.labelReady===false)failureStage='missing_label_id'; else if(current.error&&safeNode('Apply Processed Label'))failureStage='apply_processed_label'; else if(current.error&&safeNode('Apply Category Label'))failureStage='apply_category_label'; else failureStage=current.failureStage||prepared.failureStage||'processing';
return [{json:{...prepared,status:'failed',failureStage,errorMessage:String(err).slice(0,500),category:prepared.category||'needs-review',source:prepared.source||'processing_failed',confidence:prepared.confidence??0,reasoning:prepared.reasoning||'Processing failed before completion.'}}];

const p=$('Prepare Final Category').first().json; const db=$input.first()?.json||{}; const ledgerWarning=Boolean(db.error); let archiveWarning=false,archiveError=null; const archiveExecuted=$('Archive Email').isExecuted;
if(archiveExecuted){const arch=$('Archive Email').first()?.json||{};archiveWarning=Boolean(arch.error);archiveError=arch.error?.message||null;}
return [{json:{status:archiveWarning?'completed_with_warnings':'completed',messageId:p.messageId||null,sender:p.sender||null,subject:p.subject||null,category:(!ledgerWarning&&db.category)?db.category:(p.category||null),source:(!ledgerWarning&&db.source)?db.source:(p.source||null),confidence:(!ledgerWarning&&db.confidence!==undefined)?db.confidence:(p.confidence??0),reasoning:(!ledgerWarning&&db.reasoning)?db.reasoning:(p.reasoning||null),errorMessage:ledgerWarning?`Gmail processed; ledger update failed: ${db.error?.message||'unknown ledger error'}`.slice(0,500):archiveWarning?`Gmail processed; archive failed: ${archiveError||db.error_message||'unknown archive error'}`.slice(0,500):(db.error_message||null),ledgerWarning,usedGeminiBudget:['ai','ai_low_confidence','ai_failed'].includes(p.source),processingMs:Date.now()-(p.processingStartMs||Date.now())}}];
